import React, { useState, useEffect } from "react";
import Navbar from "../components/Navbar";
import axios from "axios";

function UploadScan() {

  const [file, setFile] = useState(null);
  const [original, setOriginal] = useState(null);
  const [mask, setMask] = useState(null);
  const [highlight, setHighlight] = useState(null);

  const [history, setHistory] = useState([]);

  // Load history from localStorage when page loads
  useEffect(() => {
    const savedHistory = localStorage.getItem("scanHistory");

    if (savedHistory) {
      setHistory(JSON.parse(savedHistory));
    }
  }, []);

  const handleUpload = async () => {

    if (!file) {
      alert("Please select an MRI image first");
      return;
    }

    const formData = new FormData();
    formData.append("file", file);

    try {

      const response = await axios.post(
        "http://localhost:5000/predict",
        formData
      );

      const orig = "data:image/png;base64," + response.data.original;
      const m = "data:image/png;base64," + response.data.mask;
      const h = "data:image/png;base64," + response.data.highlight;

      setOriginal(orig);
      setMask(m);
      setHighlight(h);

      const newScan = {
        id: Date.now(),
        original: orig,
        mask: m,
        highlight: h
      };

      const updatedHistory = [newScan, ...history];

      setHistory(updatedHistory);

      // Save history in localStorage
      localStorage.setItem("scanHistory", JSON.stringify(updatedHistory));

    } catch (error) {
      console.error(error);
      alert("Prediction failed");
    }
  };

  const loadScan = (scan) => {
    setOriginal(scan.original);
    setMask(scan.mask);
    setHighlight(scan.highlight);
  };

  const clearHistory = () => {
    localStorage.removeItem("scanHistory");
    setHistory([]);
  };

  return (

    <>
      <Navbar />

      <div className="container-fluid mt-4">

        <div className="row">

          {/* History Panel */}

          <div className="col-md-3 border-end">

            <h5>Scan History</h5>

            {history.length === 0 && (
              <p>No scans yet</p>
            )}

            {history.map((scan, index) => (

              <div
                key={scan.id}
                className="p-2 border mb-2"
                style={{ cursor: "pointer" }}
                onClick={() => loadScan(scan)}
              >
                Scan {index + 1}
              </div>

            ))}

            {history.length > 0 && (
              <button
                className="btn btn-danger btn-sm mt-3"
                onClick={clearHistory}
              >
                Clear History
              </button>
            )}

          </div>

          {/* Upload Section */}

          <div className="col-md-9">

            <h3>Upload MRI Scan</h3>

            <input
              type="file"
              className="form-control mb-3"
              onChange={(e) => setFile(e.target.files[0])}
            />

            <button
              className="btn btn-primary"
              onClick={handleUpload}
            >
              Predict
            </button>

            <div className="row mt-4">

              {original && (
                <div className="col-md-4 text-center">
                  <h5>Uploaded MRI</h5>
                  <img src={original} alt="original" width="220" />
                </div>
              )}

              {mask && (
                <div className="col-md-4 text-center">
                  <h5>Tumor Mask</h5>
                  <img src={mask} alt="mask" width="220" />
                </div>
              )}

              {highlight && (
                <div className="col-md-4 text-center">
                  <h5>Tumor Highlight</h5>
                  <img src={highlight} alt="highlight" width="220" />
                </div>
              )}

            </div>

          </div>

        </div>

      </div>

    </>
  );
}

export default UploadScan;
